%pyspark
# Find similar words in schinese (interpretability for Word2Vec)

w2v_model = model_w2v_zh.stages[0]

# Find words similar to key sentiment terms — this is the cool Word2Vec demo
test_words = ["不错", "垃圾", "好玩", "卡", "推荐", "刺激"]

for word in test_words:
    try:
        similar = w2v_model.findSynonyms(word, 8).collect()
        print(f"\nWords similar to '{word}':")
        for row in similar:
            print(f"  {row['word']:<20s}  similarity={row['similarity']:.4f}")
    except Exception as e:
        print(f"\n'{word}' not in vocabulary or error: {e}")
